  _boardsDiffer(other) {
    for (let r = 0; r < 4; r++) {
      for (let c = 0; c < 4; c++) {
        if (this.board[r][c] !== other[r][c]) {
          return true;
        }
      }
    }
    return false;
  }

  _spawnTile() {
    if (this.spawnQueue.length > 0) {
      const spawn = this.spawnQueue.shift();
      this.board[spawn.r][spawn.c] = spawn.v;
    }
  }

  // Helper: process a single row moving left, merging, and updating score
  // Returns the new row array
  _processLine(line) {
    // Remove zeros (slide)
    let tiles = line.filter(v => v !== 0);
    let scoreGain = 0;
    let merged = false;
    const result = [];

